1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const LOYALTY_DISCOUNT_RATE = 0.2;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const BLOCK_OF_3_PRICE = 60;
9	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	export function processScenario(scenario: any): any {
21	  const step = scenario.steps[0];
22	  let basePremium = 0;
23	  const typeCounts: Record<string, number> = {};
24	  for (const item of step.items) {
25	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
26	  }
27	  for (const [type, count] of Object.entries(typeCounts)) {
28	    const isComponentType = COMPONENT_TYPES.has(type);
29	    const formsBlockOf3 = count === 3 && isComponentType;
30	    if (formsBlockOf3) {
31	      basePremium += BLOCK_OF_3_PRICE;
32	    } else {
33	      basePremium += count * BASE_PREMIUM[type];
34	    }
35	  }
36	  let curseSurcharge = 0;
37	  let highEnchantmentSurcharge = 0;
38	  for (const item of step.items) {
39	    if (item.cursed) {
40	      curseSurcharge += BASE_PREMIUM[item.type] * CURSE_SURCHARGE_RATE;
41	    }
42	    if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
43	      highEnchantmentSurcharge += BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
44	    }
45	  }
46	  let loyaltyDiscount = 0;
47	  if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
48	    loyaltyDiscount = basePremium * LOYALTY_DISCOUNT_RATE;
49	  }
50	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
51	  const premium = basePremium + curseSurcharge + highEnchantmentSurcharge - loyaltyDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
52	  return { results: [{ premium }] };
53	}
